configuration.jsScript:
var message = []; // create a new message to incorporate
/* define constants of threshold to verify if a data is correct */
var MINTEMPERATURETHRESHOLD = -20; // °C
var MAXTEMPERATURETHRESHOLD = 70;
var MINWEIGHTTHRESHOLD = 0; // kg
var MAXWEIGHTTHRESHOLD = 30;
var MINHUMIDITYTHRESHOLD = 0; // %
var MAXHUMIDITYTHRESHOLD = 100;
var MINNOISEFREQUENCYTHRESHOLD = 0; // Hz
var MAXNOISEFREQUENCYTHRESHOLD = 500;
var MINNOISEINTENSITYTHRESHOLD = 0; // dB 
var MAXNOISEINTENSITYTHRESHOLD = 120;

/* for each message check
if it's over the threshold so as to eliminate it */
var check; // create a boolean variable
for(var singleMeasure in msg){
    check = true;

    if("temperature" in singleMeasure && (singleMeasure.temperature<MINTEMPERATURETHRESHOLD || singleMeasure.temperature>MAXTEMPERATURETHRESHOLD))
        check = false;
    else if("humidity" in singleMeasure && (singleMeasure.humidity<MINHUMIDITYTHRESHOLD || singleMeasure.humidity>MAXHUMIDITYTHRESHOLD))
        check = false;
    else if("weight" in singleMeasure && (singleMeasure.weight<MINWEIGHTTHRESHOLD || singleMeasure.weight>MAXWEIGHTTHRESHOLD))
        check = false;
    else if("noise_frequency" in singleMeasure && (singleMeasure.noise_frequency<MINNOISEFREQUENCYTHRESHOLD || singleMeasure.noise_frequency>MAXNOISEFREQUENCYTHRESHOLD))
        check = false;
    else if("noise_frequency" in singleMeasure && (singleMeasure.noise_intensity<MINNOISEINTENSITYTHRESHOLD || singleMeasure.noise_intensity>MAXNOISEINTENSITYTHRESHOLD))
        check = false;

    if(check)
        message.push(singleMeasure);
}

return {msg: message, metadata: metadata, msgType: msgType};

/* tolerate if the data is a single object and 
transform it into an array */
var dataArray = Array.isArray(msg) ? msg : [msg];

return {msg: dataArray, metadata: metadata, msgType: msgType};

/* variable definition */
var currentIndex = -1, currentKey, telemetryList, check = true, result = true;

currentKey = Object.keys(msg)[0]; // get the first and only key

/* get the list of telemetries
and find the telemetry that match the timestamp */
if(!(currentKey in metadata))
    check = false;
else{
    telemetryList = JSON.parse(metadata[currentKey]);
    currentIndex = telemetryList.findIndex(singleTelemetry => Number(singleTelemetry.ts) === Number(metadata.ts));   
}

/* control if a telemetry has been found,
otherwise it's not possible to compare it with other telemetries */
if(currentIndex<0)
    check=false;

/* control if the general average 
has been found in the common asset */
if(!("general_"+currentKey in metadata))
    check=false;

/* control if the message is closer to the average, otherwise
it's not possible to replace the telemetry */
if(check && Math.abs(msg[currentKey] - Number(metadata["general_"+currentKey]))>=Math.abs(Number(telemetryList[currentIndex].value) - Number(metadata["general_"+currentKey])))
    result = false;

/* copy the result to metadata and
return the message */
metadata.valid = result;
metadata.sameTelemetry = currentIndex;

return {msg: msg, metadata: metadata, msgType: msgType};

/* ADDITION TO THE CODE */
/* before confirming the validity of the telemetry, 
control if the telemetry is among the allowed ones,
if the list has been set */
if("shared_allowed_telemetry_keys" in metadata && metadata.shared_allowed_telemetry_keys != null && metadata.shared_allowed_telemetry_keys != undefined){
    var keyList = JSON.parse(metadata.shared_allowed_telemetry_keys);  
    if(!keyList.includes(Object.keys(msg)[0])) // verify if the keys has been added
        return ['invalid_key'];
}

var result = JSON.parse(metadata.valid); // add this to get the boolean

if(result)
    return ['valid'];


return ['dropped'];

configuration.tbelScript:
function nextRelation(metadata, msg) {
    return ['one','nine'];
}
if(msgType == 'POST_TELEMETRY_REQUEST') {
    return ['two'];
}
return nextRelation(metadata, msg);

configuration.alarmDetailsBuildJs:
var details = {};
if (metadata.prevAlarmDetails) {
    details = JSON.parse(metadata.prevAlarmDetails);
    //remove prevAlarmDetails from metadata
    delete metadata.prevAlarmDetails;
    //now metadata is the same as it comes IN this rule node
}


return details;

